def get_smallest_string(s: str, k: int) -> str:
    res = list(s)
    for i, ch in enumerate(res):
        dist_to_a = min(ord(ch) - ord('a'), ord('a') - ord(ch) + 26)
        if dist_to_a <= k:
            res[i] = 'a'
            k -= dist_to_a
        else:
            # move forward only as much as k allows
            new_char = chr(ord(ch) - k)
            res[i] = new_char
            break
    return ''.join(res)
